// =======================================================
// === 1. PARSE E NORMALIZAÇÃO DE DADOS ===
// =======================================================
let filtros = {};
try {
  const raw = $json.output || $json;
  filtros = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  console.log('❌ Erro ao parsear filtros:', e);
  filtros = {};
}

// Helpers SQL
const escapeSql = (v) => v ? String(v).replace(/'/g, "''") : null;
const toIn = (arr) => arr.map(v => `'${escapeSql(v)}'`).join(', ');

// =======================================================
// === 2. MAPEAMENTO DE CAMPOS (DE/PARA) ===
// =======================================================
const mapCol = {
  'area': 'Área',
  'departamento': 'Departamento', 
  'centro_de_custo': 'Centro_de_Custo',
  'cargo': 'Cargo',
  'empresa': 'Nome_da_Empresa',
  'sexo': 'Sexo',
  'cidade': 'Cidade',
  'estado': 'Estado',
  'estado_civil': 'Estado_Civil',
  'status': 'Situação',    // Traduz "status" do agente para "Situação" do banco
  'matricula': 'Matrícula',
  'data_nascimento': 'Data_de_Nascimento',
  'data_admissao': 'Data_de_Admissão',
  'data_desligamento': 'Data_Desligamento',
  'pcd': 'PCD',
  'cota_aprendiz': 'Cargo_Conta_para_Cota_Aprendiz',
  'cnpj': 'CNPJ_de_Vínculo',
  'avaliacao_desempenho': 'Avaliação_de_Desempenho_nota',
  'tipo_contrato': 'Tipo_Contrato',
  'gestor': 'Nome_do_Gestor',
  'matricula_gestor': 'Matrícula_do_Gestor',
  'saldo_ferias': 'Saldo_de_Férias_dias',
  'periodo_aquisitivo': 'Período_Aquisitivo_Férias',
  'conta_bancaria': 'Conta',
  'tipo_conta_bancaria': 'Tipo_Conta'
};

// Gerador de WHERE dinâmico
const filtroTxt = (alias, campoAgente, valor) => {
  if (!valor) return '';
  const colunaReal = mapCol[campoAgente.toLowerCase()] || campoAgente;

  if (Array.isArray(valor)) {
    return ` AND ${alias}.[${colunaReal}] IN (${toIn(valor)})`;
  }
  return ` AND ${alias}.[${colunaReal}] = '${escapeSql(valor)}'`;
};

// === FÓRMULA GLOBAL DE FAIXA ETÁRIA (DISPONÍVEL PARA TODOS OS CENÁRIOS) ===
const caseFaixaEtaria = `
    CASE 
        WHEN DATEDIFF(hour, c.[Data_de_Nascimento], GETDATE())/8766 BETWEEN 14 AND 24 THEN '14-24'
        WHEN DATEDIFF(hour, c.[Data_de_Nascimento], GETDATE())/8766 BETWEEN 25 AND 34 THEN '25-34'
        WHEN DATEDIFF(hour, c.[Data_de_Nascimento], GETDATE())/8766 BETWEEN 35 AND 44 THEN '35-44'
        ELSE '45+' 
    END`;

// =======================================================
// === 3. TRATAMENTO DE DATAS ===
// =======================================================
// Converte MM/AAAA para int YYYYMM (Para tabela Rubricas)
const mesParaInt = (m) => {
    if (!m) return null;
    const [mes, ano] = m.split('/');
    return parseInt(ano + mes);
};

// Gera filtro de data para Rubricas (SQL Server: Inteiro YYYYMM)
const filtroPeriodoRubrica = () => {
    // Se o agente não mandou data, assume ultimos 3 meses (fallback)
    if (!filtros.mes_inicio) return ` AND CAST(RIGHT(r.[Mes_ref_folha],4) + LEFT(r.[Mes_ref_folha],2) AS INT) >= ${new Date().getFullYear()}${String(new Date().getMonth() - 2).padStart(2,'0')}`;

    const inicio = mesParaInt(filtros.mes_inicio);
    const fim = mesParaInt(filtros.mes_fim);
    return ` AND CAST(RIGHT(r.[Mes_ref_folha],4) + LEFT(r.[Mes_ref_folha],2) AS INT) BETWEEN ${inicio} AND ${fim}`;
};

// Datas ISO para tabela Colaboradores (Admissão/Desligamento)
const dataInicioISO = filtros.mes_inicio ? `${filtros.mes_inicio.split('/')[1]}-${filtros.mes_inicio.split('/')[0]}-01` : '2023-01-01';
const dataFimISO = filtros.mes_fim ? `${filtros.mes_fim.split('/')[1]}-${filtros.mes_fim.split('/')[0]}-28` : '2025-12-31';

// =======================================================
// === 4. LÓGICA DE DECISÃO DA QUERY ===
// =======================================================

// Definição da Intenção Principal
const intencao = filtros.intencao || 'financeiro';
const metrica = filtros.metrica || 'total';
// Detecta se a pergunta é sobre reajuste/convenção
const termoBusca = (filtros.termo_busca_rubrica || "").toString().toLowerCase();
const ehCalculoReajuste = termoBusca.includes('reajuste') || termoBusca.includes('convenção') || termoBusca.includes('dissídio');

// Função Helper para padronizar o retorno
const responder = (query, modo) => {
    return [{
        json: {
            query: query,
            filtrosAplicados: filtros, // <--- AQUI ESTÁ O QUE VOCÊ PRECISA
            mensagem_grafico: filtros.logica_aplicada || "Dados filtrados conforme solicitação.",
            modo: modo
        }
    }];
};

// =======================================================
// === CENÁRIO ESPECIAL: CONSULTA ESPECÍFICA DE COLABORADOR ===
// =======================================================
// (ATUALIZADO) Verifica se tem Nome Exato OU Matrícula
const temIdentificadorUnico = (filtros.colaborador && !filtros.busca_colaborador_fuzzy) || (filtros.matricula);

if (temIdentificadorUnico) {

    // 1. Define quem estamos buscando
    let whereIdentificador = '';
    if (filtros.matricula) {
        const mat = Array.isArray(filtros.matricula) ? filtros.matricula[0] : filtros.matricula;
        whereIdentificador = `c.[Matrícula] = '${escapeSql(mat)}'`;
    } else {
        whereIdentificador = `c.[Nome] = '${escapeSql(filtros.colaborador[0])}'`;
    }

    // Campos cadastrais extras para enriquecer a resposta (Gestor, Férias, Banco, Performance)
    const colsCadastrais = `
        c.[Nome_do_Gestor], 
        c.[Saldo_de_Férias_dias], 
        c.[Período_Aquisitivo_Férias],
        c.[Avaliação_de_Desempenho_nota],
        c.[Conta],
        c.[Tipo_Conta],
        c.[CNPJ_de_Vínculo],             
        c.[PCD],                        
        c.[Cargo_Conta_para_Cota_Aprendiz] 
    `;

    // CASO A: "Qual o salário?" (Foco no Salário Contratual)
    const isSalarioFixoQuery = filtros.tipo_custo && 
                               filtros.tipo_custo.length === 1 && 
                               filtros.tipo_custo[0].toLowerCase() === 'salário';

    if (isSalarioFixoQuery) {
        const query = `
            SELECT 
                c.[Nome], c.[Matrícula], c.[Cargo],
                c.[Salário] AS Salario_Contratual_Base,
                ${colsCadastrais}, -- Traz dados extras caso o usuário pergunte depois
                r.[Mes_ref_folha],
                SUM(r.[Valor]) AS Total_Pago_Salario
            FROM [RhTech_fake_Colaboradores] c
            LEFT JOIN [vw_Rubricas_Classificadas] r 
                ON REPLACE(REPLACE(c.[CPF_Titular],'.',''),'-','') = r.[CPF]
            WHERE 
                ${whereIdentificador}
                ${filtroTxt('c', 'empresa', filtros.empresa)}
                AND (r.[Tipo_Custo] = 'Salário' OR r.[Tipo_Custo] IS NULL)
                ${filtroPeriodoRubrica()}
            GROUP BY 
                c.[Nome], c.[Matrícula], c.[Cargo], c.[Salário], r.[Mes_ref_folha],
                ${colsCadastrais} -- Agrupa pelos novos campos
            ORDER BY 
                r.[Mes_ref_folha] DESC;
        `;
        return responder(query, "detalhe_salario_colaborador");
    } 

    // CASO B: "Quanto gastei?" ou Perguntas Gerais (Gestor, Férias, etc)
    else {
        const query = `
            SELECT
                c.[Nome], c.[Matrícula], c.[Cargo],
                ${colsCadastrais}, -- Dados extras disponíveis para o Agente usar
                r.[Mes_ref_folha],
                r.[Código_Rubrica],
                r.[Descrição_Rubrica],
                r.[Tipo_Custo],
                SUM(r.[Valor]) AS Valor_Rubrica
            FROM vw_Rubricas_Classificadas r
            INNER JOIN [RhTech_fake_Colaboradores] c 
                ON REPLACE(REPLACE(c.[CPF_Titular],'.',''),'-','') = r.[CPF]
            WHERE 1 = 1
                AND ${whereIdentificador}
                ${filtroTxt('c', 'empresa', filtros.empresa)}
                ${filtroTxt('c', 'area', filtros.area)}
                ${filtroPeriodoRubrica()}
                ${filtros.tipo_custo ? `AND r.[Tipo_Custo] IN (${toIn(filtros.tipo_custo)})` : ''}

            GROUP BY
                c.[Nome], c.[Matrícula], c.[Cargo],
                ${colsCadastrais},
                r.[Mes_ref_folha], r.[Código_Rubrica], r.[Descrição_Rubrica], r.[Tipo_Custo]
            ORDER BY
                c.[Nome], r.[Mes_ref_folha] DESC, Valor_Rubrica DESC;
        `;
        return responder(query, "detalhe_custo_colaborador");
    }
}

// =======================================================
// === CENÁRIO: PERFORMANCE (MÉDIA DE AVALIAÇÃO) ===
// =======================================================
// Se o filtro de avaliação estiver preenchido (ex: "Qual a nota do time?")
if (filtros.avaliacao_desempenho) {
  let agrupadores = filtros.agrupamento || [];

  // Performance é um dado cadastral atual (tabela colaboradores), então removemos 'Mes' se vier
  agrupadores = agrupadores.filter(a => a !== 'Mes');

  // Monta Select e Group By
  const colsSelect = agrupadores.map(a => {
      if (a.toLowerCase() === 'faixa_etaria') return `${caseFaixaEtaria} AS Faixa_Etaria`;
      return `c.[${mapCol[a.toLowerCase()] || a}]`;
  }).join(', ');

  const groupByCols = agrupadores.map(a => {
      if (a.toLowerCase() === 'faixa_etaria') return caseFaixaEtaria;
      return `c.[${mapCol[a.toLowerCase()] || a}]`;
  }).join(', ');

  const groupBy = agrupadores.length > 0 ? `GROUP BY ${groupByCols}` : '';

  // Se tiver agrupamento, ordena pela melhor nota. Se não, sem ordem.
  const orderBy = agrupadores.length > 0 ? 'ORDER BY Media_Nota DESC' : '';

  const query = `
    SELECT 
        ${colsSelect ? colsSelect + ',' : ''} 
        -- Cast para FLOAT para garantir que a média tenha casas decimais (ex: 85.5)
        AVG(CAST(c.[Avaliação_de_Desempenho_nota] AS FLOAT)) as Media_Nota, 
        MIN(c.[Avaliação_de_Desempenho_nota]) as Nota_Minima,
        MAX(c.[Avaliação_de_Desempenho_nota]) as Nota_Maxima,
        COUNT(*) as Qtd_Pessoas_Avaliadas
    FROM [RhTech_fake_Colaboradores] c
    WHERE 1=1
        -- Consideramos apenas Ativos para a média fazer sentido
        AND (c.[Situação] = 'Ativo' OR c.[Situação] IS NULL)
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${filtroTxt('c', 'cargo', filtros.cargo)}
        ${filtroTxt('c', 'centro_de_custo', filtros.centro_de_custo)}
        ${filtroTxt('c', 'sexo', filtros.sexo)}
    ${groupBy}
    ${orderBy};
  `;

  return responder(query, "performance_analise");
}

// --- CENÁRIO 1: BUSCA FUZZY (Prioridade Alta) ---
// Se o agente detectou que precisa buscar nome parecido
if (filtros.colaborador && filtros.busca_colaborador_fuzzy && !filtros.matricula) {
  const termos = Array.isArray(filtros.colaborador) ? filtros.colaborador : [filtros.colaborador];
  const termo = termos[0]; 

  const query = `
    SELECT DISTINCT TOP 10
      c.[Nome],
      c.[Matrícula],
      c.[Cargo],
      c.[Área],
      -- O SQL Server exige que a lógica de ordenação esteja no SELECT quando se usa DISTINCT
      CASE WHEN c.[Nome] LIKE '%${escapeSql(termo)}%' THEN 0 ELSE 1 END AS Relevancia
    FROM [RhTech_fake_Colaboradores] c
    WHERE 1=1
      AND (
          c.[Nome] LIKE '%${escapeSql(termo)}%' 
          OR SOUNDEX(c.[Nome]) = SOUNDEX('${escapeSql(termo)}')
      )
      ${filtroTxt('c', 'empresa', filtros.empresa)}
    ORDER BY 
      Relevancia, -- Ordena pela coluna criada acima (0 = Match Exato, 1 = Fonético)
      c.[Nome];
  `;
  return responder(query, "busca_fuzzy");
}

// --- CENÁRIO 2: HEADCOUNT (Evolução Temporal e Snapshot) ---
if (intencao === 'headcount') {
  let agrupadores = filtros.agrupamento || [];

  // Força 'Mes' aparecer SEMPRE no Headcount. 
  // Isso garante que, mesmo filtrando "Março" ou "Set e Out", o retorno tenha a coluna Mês explicita.
  if (!agrupadores.includes('Mes')) {
      agrupadores = ['Mes', ...agrupadores];
  }

  // 2. Monta Colunas de Seleção (Adiciona suporte a Mês e Faixa Etária)
  const colsSelect = agrupadores.map(a => {
      if (a === 'Mes') return `r.[Mes_ref_folha]`; // Pega Mês da tabela de Rubricas
      // Se o agrupamento for 'tipo_custo', pega da View (r), não de Colaboradores (c)
      if (a.toLowerCase() === 'tipo_custo') return `r.[Tipo_Custo]`;

      if (a.toLowerCase() === 'faixa_etaria') return `${caseFaixaEtaria} AS Faixa_Etaria`;
      return `c.[${mapCol[a.toLowerCase()] || a}]`;
  }).join(', ');

  // 3. Monta Group By (Usa a mesma lógica do Case para agrupar corretamente)
  const groupByCols = agrupadores.map(a => {
      if (a === 'Mes') return `r.[Mes_ref_folha]`;
      if (a.toLowerCase() === 'faixa_etaria') return caseFaixaEtaria;
      return `c.[${mapCol[a.toLowerCase()] || a}]`;
  }).join(', ');

  const groupBy = agrupadores.length > 0 ? `GROUP BY ${groupByCols}` : '';

  // 4. Ordenação Temporal (Se pedir Mês a Mês, ordena pela data)
  let orderBy = 'Total_Colaboradores DESC';
  if (agrupadores.includes('Mes')) {
      orderBy = 'CAST(RIGHT(LTRIM(RTRIM(r.[Mes_ref_folha])),4) + LEFT(LTRIM(RTRIM(r.[Mes_ref_folha])),2) AS INT)';
  }

  // 5. QUERY FINAL (Com JOIN para pegar histórico)
  const query = `
    SELECT 
        ${colsSelect ? colsSelect + ',' : ''} 
        COUNT(DISTINCT c.[CPF_Titular]) as Total_Colaboradores
    FROM [RhTech_fake_Rubricas] r
    INNER JOIN [RhTech_fake_Colaboradores] c 
        ON REPLACE(REPLACE(REPLACE(c.[CPF_Titular], '.', ''), '-', ''), ' ', '') = REPLACE(REPLACE(REPLACE(r.[CPF], '.', ''), '-', ''), ' ', '')
    WHERE 1=1
        ${filtroPeriodoRubrica()} -- Filtra pelos meses solicitados
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${filtroTxt('c', 'sexo', filtros.sexo)}
        ${filtroTxt('c', 'cidade', filtros.cidade)}
        ${filtroTxt('c', 'status', filtros.status)}
    ${groupBy}
    ORDER BY ${orderBy};
  `;
  return responder(query, "headcount");
}

// --- CENÁRIO 3: TURNOVER (Admissão/Desligamento) ---
if (intencao === 'turnover') {
  const agrupadores = filtros.agrupamento || [];

  // Função helper para montar colunas de agrupamento dinamicamente 
  // (Detecta se é Trimestre/Ano ou campo normal)
  const buildGroupCols = (dateCol) => {
      if (agrupadores.length === 0) return { select: '', group: '', order: '' };

      const selectParts = [];
      const groupParts = [];

      agrupadores.forEach(a => {
          const campo = a.toLowerCase();

          if (campo === 'trimestre') {
             // Extrai Ano e Trimestre da data fornecida (dateCol) para comparação anual
             selectParts.push(`YEAR(${dateCol}) AS Ano, DATEPART(QUARTER, ${dateCol}) AS Trimestre`);
             groupParts.push(`YEAR(${dateCol}), DATEPART(QUARTER, ${dateCol})`);
          } else if (campo === 'mes') {
             selectParts.push(`FORMAT(${dateCol}, 'MM/yyyy') AS Mes`);
             groupParts.push(`FORMAT(${dateCol}, 'MM/yyyy')`);
          } else if (campo === 'faixa_etaria') {
             selectParts.push(`${caseFaixaEtaria} AS Faixa_Etaria`);
             groupParts.push(caseFaixaEtaria);
          } else {
             const colReal = `c.[${mapCol[campo] || a}]`;
             selectParts.push(colReal);
             groupParts.push(colReal);
          }
      });

      return {
          select: selectParts.length > 0 ? ', ' + selectParts.join(', ') : '',
          group: groupParts.length > 0 ? 'GROUP BY ' + groupParts.join(', ') : '',
          // Se tiver Ano/Trimestre, ordena cronologicamente
          order: groupParts.some(g => g.includes('YEAR')) ? 'ORDER BY Ano, Trimestre' : '' 
      };
  };

  // CASO 1: SEM AGRUPAMENTO (Query Simples com Ativos)
  if (agrupadores.length === 0) {
      const query = `
        SELECT 'Admissões' as Tipo, COUNT(*) as Qtd FROM [RhTech_fake_Colaboradores] c WHERE c.[Data_de_Admissão] BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}') ${filtroTxt('c', 'empresa', filtros.empresa)}
        UNION ALL
        SELECT 'Desligamentos' as Tipo, COUNT(*) as Qtd FROM [RhTech_fake_Colaboradores] c WHERE c.[Data_Desligamento] BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}') ${filtroTxt('c', 'empresa', filtros.empresa)}
        UNION ALL
        SELECT 'Ativos_Total' as Tipo, COUNT(*) as Qtd FROM [RhTech_fake_Colaboradores] c WHERE (c.[Situação] = 'Ativo' OR c.[Situação] IS NULL) ${filtroTxt('c', 'empresa', filtros.empresa)};
      `;
      return responder(query, "turnover_simples");
  } 

  // CASO 2: COM AGRUPAMENTO (Departamento, Trimestre, etc)
  // Removemos "Ativos Total" porque não faz sentido somar estoque atual agrupado por datas passadas
  else {
      const partsAdmissao = buildGroupCols('c.[Data_de_Admissão]');
      const partsDesligamento = buildGroupCols('c.[Data_Desligamento]');

      const query = `
        SELECT 'Admissões' as Tipo ${partsAdmissao.select}, COUNT(*) as Qtd
        FROM [RhTech_fake_Colaboradores] c
        WHERE c.[Data_de_Admissão] BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}')
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${partsAdmissao.group}

        UNION ALL

        SELECT 'Desligamentos' as Tipo ${partsDesligamento.select}, COUNT(*) as Qtd
        FROM [RhTech_fake_Colaboradores] c
        WHERE c.[Data_Desligamento] BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}')
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${partsDesligamento.group}

        ${partsAdmissao.order}
      `;
      return responder(query, "turnover_detalhado");
  }
}

// =======================================================
// === CENÁRIO 5 (NOVO): CÁLCULO DE REAJUSTE/DISSÍDIO ===
// =======================================================
if (ehCalculoReajuste) {
   // Esta query calcula a média salarial Mês a Mês e mostra a variação percentual.
   // Isso permite identificar visualmente onde houve o salto do dissídio.
   const query = `
    WITH SalarioMensal AS (
        SELECT 
            r.[Mes_ref_folha],
            -- Converte mes para int para ordenar: 01/2024 -> 202401
            CAST(RIGHT(LTRIM(RTRIM(r.[Mes_ref_folha])),4) + LEFT(LTRIM(RTRIM(r.[Mes_ref_folha])),2) AS INT) as Mes_Int,
            AVG(r.[Valor]) as Media_Salarial,
            SUM(r.[Valor]) as Folha_Total
        FROM [vw_Rubricas_Classificadas] r -- Usa a View para garantir categoria
        INNER JOIN [RhTech_fake_Colaboradores] c 
            ON REPLACE(REPLACE(REPLACE(c.[CPF_Titular], '.', ''), '-', ''), ' ', '') = REPLACE(REPLACE(REPLACE(r.[CPF], '.', ''), '-', ''), ' ', '')
        WHERE 1=1
            AND r.[Tipo_Custo] = 'Salário' -- Filtra apenas Salário Base
            ${filtroPeriodoRubrica()}
            ${filtroTxt('c', 'empresa', filtros.empresa)}
            ${filtroTxt('c', 'area', filtros.area)}
            ${filtroTxt('c', 'departamento', filtros.departamento)}
        GROUP BY r.[Mes_ref_folha]
    )
    SELECT 
        Mes_ref_folha,
        Media_Salarial,
        Folha_Total,
        LAG(Media_Salarial) OVER (ORDER BY Mes_Int) as Media_Mes_Anterior,

        -- Cálculo da Variação %
        CASE 
            WHEN LAG(Media_Salarial) OVER (ORDER BY Mes_Int) IS NULL THEN 0 
            ELSE ((Media_Salarial - LAG(Media_Salarial) OVER (ORDER BY Mes_Int)) / LAG(Media_Salarial) OVER (ORDER BY Mes_Int)) * 100 
        END as Percentual_Reajuste_Estimado

    FROM SalarioMensal
    ORDER BY Mes_Int;
   `;
   return responder(query, "calculo_reajuste");
}

// --- CENÁRIO 4: FINANCEIRO (Custo, Rubricas, Rankings) ---
// Prepara Filtros de Custo (Rubrica Específica vs Categoria)
let whereRubrica = '';
// === MELHORIA DE VISUALIZAÇÃO ===
// Só mostra o nome detalhado da rubrica se NÃO houver outro agrupamento (ex: Estado Civil).
const showRubrica = !!filtros.termo_busca_rubrica && (!filtros.agrupamento || filtros.agrupamento.length === 0);

// === OTIMIZAÇÃO: Define qual tabela usar ===
let tabelaAlvo = '[RhTech_fake_Rubricas]'; 
let usaView = false;

// Variáveis para controlar a Query Composta (Total + Categorias)
let whereTermo = '';
let whereTipo = '';
let incluirTotal = false; // Flag para saber se precisamos calcular o TOTAL GERAL

// 1. Busca Específica (Texto) - Mantém tabela bruta
if (filtros.termo_busca_rubrica) {
    const termos = Array.isArray(filtros.termo_busca_rubrica) ? filtros.termo_busca_rubrica : [filtros.termo_busca_rubrica];
    const likeClauses = termos.map(t => 
        `(r.[Descrição_Rubrica] LIKE '%${escapeSql(t)}%' OR r.[Descrição_Natureza_Rubrica] LIKE '%${escapeSql(t)}%')`
    );
    whereTermo = ` AND (${likeClauses.join(' OR ')})`;
    tabelaAlvo = '[RhTech_fake_Rubricas]'; 
    usaView = false;
} 
// 2. Busca por Categoria OU Genérica (ALTERADO: Sempre usa View para ter detalhamento)
else {
    // SEMPRE usa a View para consultas gerais para permitir quebra por Tipo_Custo (Passos Intermediários)
    tabelaAlvo = '[vw_Rubricas_Classificadas]';
    usaView = true;

    if (filtros.tipo_custo) {
        let tipos = Array.isArray(filtros.tipo_custo) ? filtros.tipo_custo : [filtros.tipo_custo];

        // VERIFICA SE O USUÁRIO PEDIU "TOTAL"
        if (tipos.some(t => t.toLowerCase() === 'total')) {
            incluirTotal = true;
            tipos = tipos.filter(t => t.toLowerCase() !== 'total');
        }

        if (tipos.length > 0) {
            whereTipo = ` AND r.[Tipo_Custo] IN (${toIn(tipos)})`;
        }
    }
}

// Junta os filtros básicos para os cenários de Ranking
whereRubrica = whereTermo + whereTipo;

// 4.1 - RANKING DE PESSOAS (PIVOTADO)
if (metrica === 'ranking' && filtros.ranking_tipo === 'pessoas') {
   const query = `
    WITH TopColaboradores AS (
        SELECT TOP 20
            c.[Nome],
            c.[Cargo],
            SUM(r.[Valor]) AS Total_Gasto_Geral
        FROM ${tabelaAlvo} r
        INNER JOIN [RhTech_fake_Colaboradores] c ON REPLACE(REPLACE(c.[CPF_Titular],'.',''),'-','') = r.[CPF]
        WHERE 1=1
          ${whereRubrica}
          ${filtroTxt('c','area', filtros.area)}
          ${filtroTxt('c','empresa', filtros.empresa)}
          ${filtroPeriodoRubrica()}
        GROUP BY c.[Nome], c.[Cargo]
        ORDER BY Total_Gasto_Geral DESC
    )
    SELECT
        topC.[Nome],
        topC.[Cargo],
        topC.[Total_Gasto_Geral],
        -- Colunas Dinâmicas (Pivot Manual)
        SUM(CASE WHEN r.[Tipo_Custo] = 'Salário' THEN r.[Valor] ELSE 0 END) AS Gasto_Salario,
        SUM(CASE WHEN r.[Tipo_Custo] = 'Horas Extras e Adicionais' THEN r.[Valor] ELSE 0 END) AS Gasto_HE_Adicionais,
        SUM(CASE WHEN r.[Tipo_Custo] = 'Comissões, Gratificações e Premiações' THEN r.[Valor] ELSE 0 END) AS Gasto_Comissoes,
        SUM(CASE WHEN r.[Tipo_Custo] = 'Férias' THEN r.[Valor] ELSE 0 END) AS Gasto_Ferias,
        SUM(CASE WHEN r.[Tipo_Custo] = '13 salário' THEN r.[Valor] ELSE 0 END) AS Gasto_13_Salario,
        SUM(CASE WHEN r.[Tipo_Custo] = 'Rescisão' THEN r.[Valor] ELSE 0 END) AS Gasto_Rescisao,
        SUM(CASE WHEN r.[Tipo_Custo] = 'Afastamento' THEN r.[Valor] ELSE 0 END) AS Gasto_Afastamento,
        SUM(CASE WHEN r.[Tipo_Custo] NOT IN ('Salário', 'Horas Extras e Adicionais', 'Comissões, Gratificações e Premiações', 'Férias', '13 salário', 'Rescisão', 'Afastamento') OR r.[Tipo_Custo] IS NULL THEN r.[Valor] ELSE 0 END) AS Outros
    FROM TopColaboradores topC
    INNER JOIN [RhTech_fake_Colaboradores] c ON c.[Nome] = topC.[Nome] AND c.[Cargo] = topC.[Cargo]
    INNER JOIN [vw_Rubricas_Classificadas] r ON REPLACE(REPLACE(c.[CPF_Titular],'.',''),'-','') = r.[CPF]
    WHERE 1=1
       ${filtroPeriodoRubrica()}
    GROUP BY topC.[Nome], topC.[Cargo], topC.[Total_Gasto_Geral]
    ORDER BY topC.[Total_Gasto_Geral] DESC;
   `;
   return responder(query, "ranking_pessoas");
}

// 4.2 - RANKING DE CATEGORIA
if (metrica === 'ranking' && filtros.ranking_tipo === 'categoria') {
    let colAgrupamento = 'c.[Área]'; 
    if (filtros.agrupamento && filtros.agrupamento.length > 0) {
        const campoAgente = filtros.agrupamento[0];
        if (campoAgente.toLowerCase() === 'tipo_custo') {
             colAgrupamento = usaView ? 'r.[Tipo_Custo]' : "'TOTAL'";
        } 
        else if (campoAgente.toLowerCase() === 'faixa_etaria') {
             colAgrupamento = caseFaixaEtaria;
        }
        else {
             const nomeColunaBanco = mapCol[campoAgente.toLowerCase()] || campoAgente;
             colAgrupamento = `c.[${nomeColunaBanco}]`;
        }
    } 
    else {
        if(filtros.departamento) colAgrupamento = 'c.[Departamento]';
        if(filtros.centro_de_custo) colAgrupamento = 'c.[Centro_de_Custo]';
        if(filtros.cargo) colAgrupamento = 'c.[Cargo]';
    }

    const query = `
      SELECT 
        ${colAgrupamento} as Categoria,
        SUM(r.[Valor]) AS Total_Gasto
      FROM ${tabelaAlvo} r
      INNER JOIN [RhTech_fake_Colaboradores] c ON REPLACE(REPLACE(c.[CPF_Titular],'.',''),'-','') = r.[CPF]
      WHERE 1=1
        ${whereRubrica}
        ${filtroTxt('c','area', filtros.area)} 
        ${filtroTxt('c','empresa', filtros.empresa)}
        ${filtroPeriodoRubrica()}
      GROUP BY ${colAgrupamento}
      ORDER BY Total_Gasto DESC;
    `;
    return responder(query, "ranking_categoria");
}

// 4.3 - CONSULTA FINANCEIRA GERAL (Total, Mês a Mês, Por Grupo)
let agrupadores = filtros.agrupamento || [];

const isRange = filtros.mes_inicio !== filtros.mes_fim;
if ((metrica === 'evolucao' || isRange) && !agrupadores.includes('Mes')) {
    agrupadores = ['Mes', ...agrupadores];
}

let filtroMatricula = '';
if (filtros.matricula) {
    const arrMatriculas = Array.isArray(filtros.matricula) ? filtros.matricula : [filtros.matricula];
    filtroMatricula = ` AND c.[Matrícula] IN (${toIn(arrMatriculas)})`;
}
let filtroNome = (filtros.colaborador && !filtros.busca_colaborador_fuzzy) ? ` AND c.[Nome] = '${escapeSql(filtros.colaborador[0])}'` : '';

let orderBy = metrica === 'media' ? 'Media_Valor DESC' : 'Total_Valor DESC';
const needsDateSort = metrica === 'evolucao' || agrupadores.includes('Mes');

if (needsDateSort) {
    orderBy = 'Mes_Sort DESC';
}

// === FUNÇÃO GERADORA DE QUERY (ALTERADA PARA DETALHAMENTO AUTOMÁTICO) ===
const montarQuery = (modoTotal) => {

    const selectParts = [];
    const groupParts = [];

    if (agrupadores.includes('Mes')) {
        selectParts.push(`r.[Mes_ref_folha]`);
        groupParts.push(`r.[Mes_ref_folha]`);
    }

    agrupadores.forEach(a => {
        if (a === 'Mes') return; 

        if (a.toLowerCase() === 'tipo_custo') {
            const col = modoTotal ? `'TOTAL' as Tipo_Custo` : (usaView ? `r.[Tipo_Custo]` : `'' as Tipo_Custo`);
            selectParts.push(col);
            if (!modoTotal && usaView) groupParts.push(`r.[Tipo_Custo]`);
            return;
        }

        if (a === 'termo_busca_rubrica') {
            selectParts.push(`r.[Descrição_Rubrica]`);
            return; 
        }

        if (a.toLowerCase() === 'faixa_etaria') {
            selectParts.push(`${caseFaixaEtaria} AS Faixa_Etaria`);
            groupParts.push(caseFaixaEtaria);
            return;
        }

        const colName = mapCol[a.toLowerCase()] || a;
        selectParts.push(`c.[${colName}]`);
        groupParts.push(`c.[${colName}]`);
    });

    const selectStr = selectParts.join(', ');
    const groupStr = groupParts.length > 0 ? groupParts.join(', ') : `r.[Mes_ref_folha]`;
    const sortColumn = needsDateSort ? `, CAST(RIGHT(LTRIM(RTRIM(r.[Mes_ref_folha])),4) + LEFT(LTRIM(RTRIM(r.[Mes_ref_folha])),2) AS INT) as Mes_Sort` : '';

    return `
      SELECT 
        ${selectStr ? selectStr + ',' : 'r.[Mes_ref_folha] as Mes,'}
        ${filtros.matricula ? 'c.[Matrícula], c.[Nome],' : ''} 

        ${showRubrica ? 'r.[Descrição_Rubrica], r.[Descrição_Natureza_Rubrica],' : ''}

        -- AQUI ESTÁ A MÁGICA: FORÇA O DETALHAMENTO POR TIPO_CUSTO SE ESTIVER USANDO A VIEW
        ${(usaView && !showRubrica && !agrupadores.includes('tipo_custo')) 
            ? (modoTotal ? "'TOTAL' as Tipo_Custo," : "r.[Tipo_Custo],") 
            : ''}

        ${metrica === 'media' 
            ? `SUM(r.[Valor]) AS Total_Valor, 
               COUNT(DISTINCT c.[CPF_Titular]) AS Qtd_Colaboradores, 
               SUM(r.[Valor]) / NULLIF(COUNT(DISTINCT c.[CPF_Titular]), 0) AS Media_Valor` 
            : `SUM(r.[Valor]) AS Total_Valor`
        }

        ${sortColumn}
      FROM ${tabelaAlvo} r 
      INNER JOIN [RhTech_fake_Colaboradores] c 
        ON REPLACE(REPLACE(REPLACE(c.[CPF_Titular], '.', ''), '-', ''), ' ', '') = REPLACE(REPLACE(REPLACE(r.[CPF], '.', ''), '-', ''), ' ', '')
      WHERE 1=1
        ${whereTermo} 
        ${modoTotal ? '' : whereTipo} 
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${filtroTxt('c', 'sexo', filtros.sexo)}
        ${filtroTxt('c', 'cidade', filtros.cidade)}
        ${filtroTxt('c', 'estado', filtros.estado)}
        ${filtroTxt('c', 'estado_civil', filtros.estado_civil)}
        ${filtroTxt('c', 'status', filtros.status)}
        ${filtroTxt('c', 'pcd', filtros.pcd)}
        ${filtroTxt('c', 'cota_aprendiz', filtros.cota_aprendiz)}
        ${filtroTxt('c', 'tipo_contrato', filtros.tipo_contrato)}
        ${filtroTxt('c', 'cnpj', filtros.cnpj)}

        ${filtroPeriodoRubrica()}
        ${filtroMatricula}
        ${filtroNome}
      GROUP BY ${groupStr} ${filtros.matricula ? ', c.[Matrícula], c.[Nome]' : ''} 
      ${(showRubrica && !agrupadores.includes('termo_busca_rubrica')) ? ', r.[Descrição_Rubrica], r.[Descrição_Natureza_Rubrica]' : ''}
      ${(usaView && !showRubrica && !agrupadores.includes('tipo_custo')) ? (modoTotal ? '' : ', r.[Tipo_Custo]') : ''}
    `;
};

// =======================================================
// === CENÁRIO 6: SIMULAÇÃO (PRIORIDADE SOBRE FINANCEIRO) ===
// =======================================================
// Se tiver valor de simulação, entra aqui MESMO que a intenção seja 'financeiro'
if (filtros.valor_simulacao && parseFloat(filtros.valor_simulacao) > 0) {

    const valorUnitario = parseFloat(filtros.valor_simulacao);

    // Precisamos contar quantos ativos existem HOJE para projetar o custo
    // Note que usamos os filtrosTxt('c'...) para respeitar Departamento = TI, etc.
    const query = `
      SELECT 
        COUNT(DISTINCT c.[CPF_Titular]) as Qtd_Colaboradores_Ativos,
        ${valorUnitario} as Valor_Unitario_Simulado,

        -- Cálculo do Impacto (Qtd * Valor)
        (COUNT(DISTINCT c.[CPF_Titular]) * ${valorUnitario}) as Aumento_Mensal_Folha,

        -- Projeção Anual (x12)
        (COUNT(DISTINCT c.[CPF_Titular]) * ${valorUnitario} * 12) as Impacto_Anual_Estimado

      FROM [RhTech_fake_Colaboradores] c
      WHERE 
        (c.[Situação] = 'Ativo' OR c.[Situação] IS NULL) -- Considera apenas quem está na casa
        ${filtroTxt('c', 'empresa', filtros.empresa)}
        ${filtroTxt('c', 'area', filtros.area)}
        ${filtroTxt('c', 'departamento', filtros.departamento)}
        ${filtroTxt('c', 'centro_de_custo', filtros.centro_de_custo)}
        ${filtroTxt('c', 'cargo', filtros.cargo)}
        ${filtroTxt('c', 'estado', filtros.estado)}
        ${filtroTxt('c', 'cidade', filtros.cidade)}
        ${filtroTxt('c', 'faixa_etaria', filtros.faixa_etaria)} -- Importante para simulações demográficas
        ${filtroTxt('c', 'tipo_contrato', filtros.tipo_contrato)}
    `;

    return responder(query, "simulacao_impacto");
}

// === MONTAGEM FINAL ===
let queryFinal = '';

if (incluirTotal && whereTipo !== '') {
    const qParte1 = montarQuery(false); 
    const qParte2 = montarQuery(true);  
    queryFinal = `${qParte1} UNION ALL ${qParte2} ORDER BY ${orderBy}`;
} 
else if (incluirTotal && whereTipo === '') {
    queryFinal = `${montarQuery(true)} ORDER BY ${orderBy}`;
}
else {
    queryFinal = `${montarQuery(false)} ORDER BY ${orderBy}`;
}

return responder(queryFinal, "financeiro_geral");

// -------------------------
// 1) Captura os dados do trigger
// -------------------------

const input = $input.first().json;

// Tudo que vem do trigger via string deve virar array:
function parseList(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  return value
    .split(";")
    .map(v => v.trim())
    .filter(v => v.length > 0);
}

// -------------------------
// 2) Captura dados das planilhas (vindos dos nodes anteriores)
// -------------------------

const parametros_folha = {
  //rubricas: $('rubricas').all().map(item => item.json),
  empresa: input.empresa || null,
  areas: parseList(input.areas),
  departamentos: parseList(input.departamentos),
  centro_de_custo: parseList(input.centro_de_custo),
  cargos: parseList(input.cargos),
};

// -------------------------
// 3) Captura a pergunta
// -------------------------

const pergunta =
  input.pergunta ||
  null;

// -------------------------
// 4) Retorna JSON consolidado
// -------------------------

return [
  {
    json: {
      pergunta,
      parametros_folha
    }
  }
];

// === 1️⃣ Agrupa todos os resultados vindos do Executar Query ===
const resultados = items.map(item => item.json);

// === 2️⃣ Extrai a pergunta e filtros do nó "Interpretar pergunta" ===
let data = {};
const criarQueryItems = $items("Criar Query");
const queryObj = criarQueryItems?.[0]?.json || {};

const query = queryObj.query ?? null;
try {
  data = JSON.parse($('Interpretar pergunta').item.json.output || '{}');
} catch (e) {
  console.log('❌ Erro ao parsear Interpretar pergunta:', e);
  data = {};
}

// === 3️⃣ Retorna tudo junto ===
return [{
  json: {
    query,
    filtros: data,
    logica: data.logica_aplicada || null,
    resultados: resultados
  }
}];

// Junta todos os outputs (cada item tem um JSON string dentro de "output")
const all = items.flatMap(item => {
  try {
    let jsonString = item.json.output;

    // Tenta encontrar conteúdo entre ```json e ```, ou usa a string inteira
    const jsonMatch = jsonString.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch) {
      jsonString = jsonMatch[1].trim();
    } else {
      // Se não encontrar blocos de código, tenta encontrar JSON entre { e }
      const jsonContent = jsonString.match(/\{[\s\S]*\}/);
      if (jsonContent) {
        jsonString = jsonContent[0].trim();
      }
    }

    return JSON.parse(jsonString);
  } catch (e) {
    console.log('Erro ao fazer parse do JSON:', e);
    return [];
  }
});

// Se o resultado for um array com apenas 1 objeto, retorna só ele
const final = Array.isArray(all) && all.length === 1 ? all[0] : all;

// Retorna no formato que o n8n espera
return [
  {
    json: final
  }
];
